import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import io from 'socket.io-client';
import './WaitingRoom.css';

const socket = io('https://zoom-clone-3-uibx.onrender.com');

function WaitingRoom({ roomId, meetingInfo, onCancel }) {
  const [waitingTime, setWaitingTime] = useState(0);
  const [message, setMessage] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    // Join waiting room socket
    socket.emit('join-waiting-room', { roomId });

    // Listen for admission
    socket.on('admitted-to-meeting', () => {
      navigate(`/room/${roomId}`);
    });

    // Listen for host messages
    socket.on('host-message', (data) => {
      setMessage(data.message);
    });

    // Timer
    const timer = setInterval(() => {
      setWaitingTime(prev => prev + 1);
    }, 1000);

    return () => {
      clearInterval(timer);
      socket.off('admitted-to-meeting');
      socket.off('host-message');
    };
  }, [roomId, navigate]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="waiting-room-container">
      <div className="waiting-room-card">
        <div className="waiting-icon">
          <i className="fas fa-hourglass-half"></i>
        </div>
        
        <h2>Waiting Room</h2>
        
        <div className="meeting-info">
          <h3>{meetingInfo?.title}</h3>
          <p>Host: {meetingInfo?.hostName}</p>
        </div>

        <div className="waiting-status">
          <p>You're in the waiting room</p>
          <p className="waiting-time">Waiting time: {formatTime(waitingTime)}</p>
        </div>

        {message && (
          <div className="host-message">
            <strong>Host message:</strong>
            <p>{message}</p>
          </div>
        )}

        <div className="waiting-actions">
          <button className="cancel-btn" onClick={onCancel}>
            Cancel
          </button>
          <button className="notify-btn" disabled>
            <i className="fas fa-bell"></i>
            Notify Host
          </button>
        </div>

        <p className="waiting-note">
          The host will let you in soon. Please wait.
        </p>
      </div>
    </div>
  );
}

export default WaitingRoom;