import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../../services/api';
import MeetingLink from './MeetingLink';
import './Meeting.css';
// import MeetingLinks from './MeetingLinks';
function CreateMeeting() {
  const [meetingDetails, setMeetingDetails] = useState({
    title: '',
    description: '',
    password: '',
    settings: {
      muteOnEntry: false,
      videoOffOnEntry: false,
      allowChat: true,
      allowScreenShare: true,
      allowUnmute: true,
      waitingRoom: false,
      maxParticipants: 100
    }
  });
  const [isCreating, setIsCreating] = useState(false);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [showLinks, setShowLinks] = useState(false);
  const [createdMeeting, setCreatedMeeting] = useState(null);
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    
    if (name.startsWith('settings.')) {
      const settingName = name.split('.')[1];
      setMeetingDetails({
        ...meetingDetails,
        settings: {
          ...meetingDetails.settings,
          [settingName]: type === 'checkbox' ? checked : value
        }
      });
    } else {
      setMeetingDetails({
        ...meetingDetails,
        [name]: value
      });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsCreating(true);
    
    try {
      const { data } = await API.post('/meetings/create', meetingDetails);
      setCreatedMeeting(data);
      setShowLinks(true);
    } catch (error) {
      console.error('Failed to create meeting:', error);
      alert('Failed to create meeting. Please try again.');
    } finally {
      setIsCreating(false);
    }
  };

  const handleCloseLinks = () => {
    setShowLinks(false);
    navigate(`/room/${createdMeeting.roomId}`);
  };

  return (
    <>
      <div className="create-meeting-container">
        <div className="create-meeting-card">
          <h2>Create New Meeting</h2>
          <p>Start a new video conference with full host controls</p>
          
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Meeting Title</label>
              <input
                type="text"
                name="title"
                value={meetingDetails.title}
                onChange={handleChange}
                placeholder={`${user?.name || 'User'}'s Meeting`}
                required
              />
            </div>
            
            <div className="form-group">
              <label>Description (Optional)</label>
              <textarea
                name="description"
                value={meetingDetails.description}
                onChange={handleChange}
                placeholder="What's this meeting about?"
                rows="3"
              />
            </div>
            
            <div className="form-group">
              <label>Password (Optional)</label>
              <input
                type="password"
                name="password"
                value={meetingDetails.password}
                onChange={handleChange}
                placeholder="Leave empty for no password"
              />
              <small className="help-text">
                Set a password to make your meeting private
              </small>
            </div>
            
            <div className="advanced-toggle">
              <button
                type="button"
                onClick={() => setShowAdvanced(!showAdvanced)}
                className="toggle-btn"
              >
                <i className={`fas fa-chevron-${showAdvanced ? 'up' : 'down'}`}></i>
                {showAdvanced ? 'Hide' : 'Show'} Advanced Settings
              </button>
            </div>
            
            {showAdvanced && (
              <div className="advanced-settings">
                <h3>
                  <i className="fas fa-cog"></i>
                  Meeting Settings
                </h3>
                
                <div className="settings-grid">
                  <div className="setting-item">
                    <label className="switch">
                      <input
                        type="checkbox"
                        name="settings.muteOnEntry"
                        checked={meetingDetails.settings.muteOnEntry}
                        onChange={handleChange}
                      />
                      <span className="slider"></span>
                    </label>
                    <span>Mute participants on entry</span>
                  </div>
                  
                  <div className="setting-item">
                    <label className="switch">
                      <input
                        type="checkbox"
                        name="settings.videoOffOnEntry"
                        checked={meetingDetails.settings.videoOffOnEntry}
                        onChange={handleChange}
                      />
                      <span className="slider"></span>
                    </label>
                    <span>Turn off video on entry</span>
                  </div>
                  
                  <div className="setting-item">
                    <label className="switch">
                      <input
                        type="checkbox"
                        name="settings.allowChat"
                        checked={meetingDetails.settings.allowChat}
                        onChange={handleChange}
                      />
                      <span className="slider"></span>
                    </label>
                    <span>Allow chat</span>
                  </div>
                  
                  <div className="setting-item">
                    <label className="switch">
                      <input
                        type="checkbox"
                        name="settings.allowScreenShare"
                        checked={meetingDetails.settings.allowScreenShare}
                        onChange={handleChange}
                      />
                      <span className="slider"></span>
                    </label>
                    <span>Allow screen sharing</span>
                  </div>
                  
                  <div className="setting-item">
                    <label className="switch">
                      <input
                        type="checkbox"
                        name="settings.allowUnmute"
                        checked={meetingDetails.settings.allowUnmute}
                        onChange={handleChange}
                      />
                      <span className="slider"></span>
                    </label>
                    <span>Allow participants to unmute</span>
                  </div>
                  
                  <div className="setting-item">
                    <label className="switch">
                      <input
                        type="checkbox"
                        name="settings.waitingRoom"
                        checked={meetingDetails.settings.waitingRoom}
                        onChange={handleChange}
                      />
                      <span className="slider"></span>
                    </label>
                    <span>Enable waiting room</span>
                  </div>
                </div>
                
                <div className="form-group">
                  <label>Max Participants</label>
                  <input
                    type="number"
                    name="settings.maxParticipants"
                    value={meetingDetails.settings.maxParticipants}
                    onChange={handleChange}
                    min="1"
                    max="1000"
                  />
                </div>
              </div>
            )}
            
            <div className="form-actions">
              <button
                type="button"
                onClick={() => navigate('/')}
                className="cancel-btn"
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={isCreating}
                className="create-btn"
              >
                {isCreating ? (
                  <>
                    <i className="fas fa-spinner fa-spin"></i>
                    Creating...
                  </>
                ) : (
                  <>
                    <i className="fas fa-video"></i>
                    Create Meeting
                  </>
                )}
              </button>
            </div>
          </form>
        </div>
      </div>

      {showLinks && createdMeeting && (
        <MeetingLink
          meetingLinks={createdMeeting.meetingLinks}
          roomId={createdMeeting.roomId}
          onClose={handleCloseLinks}
        />
      )}
    </>
  );
}

export default CreateMeeting;