import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import MeetingLinksList from './Meeting/MeetingLinksList';
import './Home.css';

function Home() {
  const [activeTab, setActiveTab] = useState('join');
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const userData = localStorage.getItem('user');
    if (userData) {
      setUser(JSON.parse(userData));
    }
  }, []);

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  if (!user) {
    return null;
  }

  return (
    <div className="home-container">
      <header className="home-header">
        <div className="header-left">
          <h1>Zoom Clone</h1>
        </div>
        <div className="header-right">
          <span className="user-name">Welcome, {user.name}!</span>
          <button onClick={logout} className="logout-btn">
            <i className="fas fa-sign-out-alt"></i>
            Logout
          </button>
        </div>
      </header>

      <div className="home-tabs">
        <button 
          className={`tab-btn ${activeTab === 'join' ? 'active' : ''}`}
          onClick={() => setActiveTab('join')}
        >
          <i className="fas fa-sign-in-alt"></i>
          Join Meeting
        </button>
        <button 
          className={`tab-btn ${activeTab === 'create' ? 'active' : ''}`}
          onClick={() => setActiveTab('create')}
        >
          <i className="fas fa-plus-circle"></i>
          Create Meeting
        </button>
        <button 
          className={`tab-btn ${activeTab === 'links' ? 'active' : ''}`}
          onClick={() => setActiveTab('links')}
        >
          <i className="fas fa-link"></i>
          My Meetings
        </button>
      </div>

      <div className="home-content">
        {activeTab === 'join' && (
          <div className="quick-join">
            <h2>Join a Meeting</h2>
            <p>Enter a meeting ID or link to join</p>
            <form onSubmit={(e) => {
              e.preventDefault();
              const meetingId = e.target.meetingId.value;
              if (meetingId) {
                navigate(`/join/${meetingId}`);
              }
            }}>
              <input
                type="text"
                name="meetingId"
                placeholder="Enter meeting ID or link"
                className="join-input"
              />
              <button type="submit" className="join-submit-btn">
                Join Now
              </button>
            </form>
            <div className="quick-actions">
              <Link to="/create" className="quick-action-link">
                <i className="fas fa-video"></i>
                Create New Meeting
              </Link>
            </div>
          </div>
        )}

        {activeTab === 'create' && (
          <div className="create-quick">
            <h2>Start a New Meeting</h2>
            <p>Create an instant meeting with full host controls</p>
            <button 
              className="create-now-btn"
              onClick={() => navigate('/create')}
            >
              <i className="fas fa-video"></i>
              Create Meeting Now
            </button>
          </div>
        )}

        {activeTab === 'links' && <MeetingLinksList />}
      </div>
    </div>
  );
}

export default Home;