import React, { useState } from 'react';
import './ParticipantForm.css';

function ParticipantForm({ roomId, meetingDetails, onSubmit, onCancel }) {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    mobile: '',
    agreeToTerms: false
  });
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === 'checkbox' ? checked : value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    
    if (!formData.name || !formData.email) {
      setError('Name and email are required');
      return;
    }
    
    if (!formData.agreeToTerms) {
      setError('You must agree to the terms');
      return;
    }
    
    // Send only the required fields
    onSubmit({
      name: formData.name,
      email: formData.email,
      mobile: formData.mobile
    });
  };

  return (
    <div className="participant-form-modal">
      <div className="participant-form-content">
        <div className="form-header">
          <h2>Join {meetingDetails?.title || 'Meeting'}</h2>
          <p>Hosted by: {meetingDetails?.hostName || 'Host'}</p>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Your Name *</label>
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              placeholder="Enter your full name"
              required
            />
          </div>

          <div className="form-group">
            <label>Email Address *</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="Enter your email"
              required
            />
          </div>

          <div className="form-group">
            <label>Mobile Number (Optional)</label>
            <input
              type="tel"
              name="mobile"
              value={formData.mobile}
              onChange={handleChange}
              placeholder="Enter your mobile number"
            />
          </div>

          <div className="form-group checkbox">
            <label>
              <input
                type="checkbox"
                name="agreeToTerms"
                checked={formData.agreeToTerms}
                onChange={handleChange}
              />
              <span>I agree to the terms and conditions</span>
            </label>
          </div>

          {error && <div className="error-message">{error}</div>}

          <div className="form-actions">
            <button type="button" className="cancel-btn" onClick={onCancel}>
              Back
            </button>
            <button type="submit" className="join-btn">
              Join Meeting
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default ParticipantForm;