import React, { useState, useEffect } from 'react';
import API from '../../services/api';
import './MeetingLinksList.css';

function MeetingLinksList() {
  const [meetings, setMeetings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [copiedId, setCopiedId] = useState(null);

  useEffect(() => {
    fetchMeetings();
  }, []);

  const fetchMeetings = async () => {
    try {
      const { data } = await API.get('/meetings/host/meetings');
      setMeetings(data);
    } catch (error) {
      console.error('Failed to fetch meetings:', error);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text, meetingId) => {
    navigator.clipboard.writeText(text);
    setCopiedId(meetingId);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const formatDate = (date) => {
    return new Date(date).toLocaleString();
  };

  if (loading) {
    return <div className="loading">Loading your meetings...</div>;
  }

  return (
    <div className="meetings-list-container">
      <div className="meetings-header">
        <h2>Your Meetings</h2>
        <button className="create-new-btn" onClick={() => window.location.href = '/create'}>
          <i className="fas fa-plus"></i>
          Create New Meeting
        </button>
      </div>

      {meetings.length === 0 ? (
        <div className="no-meetings">
          <i className="fas fa-video-slash"></i>
          <p>You haven't created any meetings yet</p>
          <button className="create-first-btn" onClick={() => window.location.href = '/create'}>
            Create Your First Meeting
          </button>
        </div>
      ) : (
        <div className="meetings-grid">
          {meetings.map((meeting) => (
            <div key={meeting._id} className="meeting-card">
              <div className="meeting-card-header">
                <h3>{meeting.title}</h3>
                <span className={`status-badge ${meeting.isActive ? 'active' : 'ended'}`}>
                  {meeting.isActive ? 'Live' : 'Ended'}
                </span>
              </div>

              <div className="meeting-card-body">
                <p className="meeting-id">
                  <strong>ID:</strong> {meeting.roomId}
                </p>
                <p className="meeting-date">
                  <i className="far fa-calendar"></i>
                  {formatDate(meeting.createdAt)}
                </p>
                <p className="participant-count">
                  <i className="fas fa-users"></i>
                  {meeting.participants?.length || 0} participants
                </p>
              </div>

              <div className="meeting-links">
                <div className="link-item">
                  <span className="link-label host">Host Link</span>
                  <div className="link-value">
                    <input 
                      type="text" 
                      value={meeting.links?.host || ''} 
                      readOnly 
                    />
                    <button 
                      className="copy-link-btn"
                      onClick={() => copyToClipboard(meeting.links?.host, `host-${meeting._id}`)}
                    >
                      <i className={`fas ${copiedId === `host-${meeting._id}` ? 'fa-check' : 'fa-copy'}`}></i>
                    </button>
                  </div>
                </div>

                <div className="link-item">
                  <span className="link-label participant">Participant Link</span>
                  <div className="link-value">
                    <input 
                      type="text" 
                      value={meeting.links?.participant || ''} 
                      readOnly 
                    />
                    <button 
                      className="copy-link-btn"
                      onClick={() => copyToClipboard(meeting.links?.participant, `part-${meeting._id}`)}
                    >
                      <i className={`fas ${copiedId === `part-${meeting._id}` ? 'fa-check' : 'fa-copy'}`}></i>
                    </button>
                  </div>
                </div>
              </div>

              <div className="meeting-card-footer">
                {meeting.isActive && (
                  <button 
                    className="join-host-btn"
                    onClick={() => window.open(meeting.links?.host, '_blank')}
                  >
                    <i className="fas fa-video"></i>
                    Join as Host
                  </button>
                )}
                <button 
                  className="copy-all-btn"
                  onClick={() => {
                    const allLinks = `Meeting: ${meeting.title}\nID: ${meeting.roomId}\nHost Link: ${meeting.links?.host}\nParticipant Link: ${meeting.links?.participant}`;
                    copyToClipboard(allLinks, `all-${meeting._id}`);
                  }}
                >
                  <i className="fas fa-copy"></i>
                  Copy All
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default MeetingLinksList;