import React, { useEffect, useRef, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import io from 'socket.io-client';
import Peer from 'simple-peer';
import './Room.css';

const socket = io('https://zoom-clone-backend.onrender.com', {
  withCredentials: true,
  transports: ['websocket', 'polling']
});

function Room() {
  const { roomId } = useParams();
  const navigate = useNavigate();
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [isAudioMuted, setIsAudioMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);
  const [participants, setParticipants] = useState([]);
  const [isHost, setIsHost] = useState(false);
  const [loading, setLoading] = useState(true);
  
  const userVideo = useRef();
  const peersRef = useRef([]);
  const user = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    if (!user) {
      navigate('/login');
      return;
    }

    // Check if user is host from URL
    const urlParams = new URLSearchParams(window.location.search);
    const hostParam = urlParams.get('host');
    setIsHost(hostParam === user.id);

    // Get user media
    navigator.mediaDevices.getUserMedia({ video: true, audio: true })
      .then(stream => {
        setLocalStream(stream);
        if (userVideo.current) {
          userVideo.current.srcObject = stream;
        }

        // Join room
        socket.emit('join-room', {
          roomId,
          userId: user.id,
          userName: user.name,
          isHost: hostParam === user.id
        });

        // Handle existing users
        socket.on('existing-users', (users) => {
          const peers = [];
          users.forEach(remoteUser => {
            const peer = createPeer(remoteUser.socketId, socket.id, stream);
            peersRef.current.push({
              peerId: remoteUser.socketId,
              peer,
              userName: remoteUser.userName
            });
            peers.push({
              peerId: remoteUser.socketId,
              peer,
              userName: remoteUser.userName
            });
          });
          setPeers(peers);
        });

        // Handle new user
        socket.on('user-connected', (newUser) => {
          const peer = addPeer(newUser.socketId, socket.id, stream);
          peersRef.current.push({
            peerId: newUser.socketId,
            peer,
            userName: newUser.userName
          });
          setPeers(prev => [...prev, {
            peerId: newUser.socketId,
            peer,
            userName: newUser.userName
          }]);
        });

        // Handle offer
        socket.on('offer', ({ offer, fromSocketId }) => {
          const peer = addPeer(fromSocketId, socket.id, stream);
          peer.signal(offer);
          peersRef.current.push({
            peerId: fromSocketId,
            peer,
            userName: 'Participant'
          });
        });

        // Handle answer
        socket.on('answer', ({ answer, fromSocketId }) => {
          const peerItem = peersRef.current.find(p => p.peerId === fromSocketId);
          if (peerItem) {
            peerItem.peer.signal(answer);
          }
        });

        // Handle ICE candidate
        socket.on('ice-candidate', ({ candidate, fromSocketId }) => {
          const peerItem = peersRef.current.find(p => p.peerId === fromSocketId);
          if (peerItem) {
            peerItem.peer.signal(candidate);
          }
        });

        // Handle user disconnect
        socket.on('user-disconnected', (socketId) => {
          const peerItem = peersRef.current.find(p => p.peerId === socketId);
          if (peerItem) {
            peerItem.peer.destroy();
          }
          peersRef.current = peersRef.current.filter(p => p.peerId !== socketId);
          setPeers(prev => prev.filter(p => p.peerId !== socketId));
        });

        setLoading(false);
      })
      .catch(err => {
        console.error('Error accessing media devices:', err);
        setLoading(false);
      });

    return () => {
      socket.off('existing-users');
      socket.off('user-connected');
      socket.off('offer');
      socket.off('answer');
      socket.off('ice-candidate');
      socket.off('user-disconnected');
      
      if (localStream) {
        localStream.getTracks().forEach(track => track.stop());
      }
      
      peersRef.current.forEach(({ peer }) => {
        if (peer) peer.destroy();
      });
    };
  }, [roomId, user?.id]);

  const createPeer = (targetSocketId, senderSocketId, stream) => {
    const peer = new Peer({
      initiator: true,
      trickle: false,
      stream,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' }
        ]
      }
    });

    peer.on('signal', signal => {
      socket.emit('offer', { targetSocketId, offer: signal });
    });

    return peer;
  };

  const addPeer = (targetSocketId, senderSocketId, stream) => {
    const peer = new Peer({
      initiator: false,
      trickle: false,
      stream,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' }
        ]
      }
    });

    peer.on('signal', signal => {
      socket.emit('answer', { targetSocketId, answer: signal });
    });

    return peer;
  };

  const toggleAudio = () => {
    if (localStream) {
      localStream.getAudioTracks()[0].enabled = !isAudioMuted;
      setIsAudioMuted(!isAudioMuted);
      socket.emit('toggle-audio', { roomId, isMuted: !isAudioMuted });
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      localStream.getVideoTracks()[0].enabled = !isVideoOff;
      setIsVideoOff(!isVideoOff);
      socket.emit('toggle-video', { roomId, isVideoOff: !isVideoOff });
    }
  };

  const leaveRoom = () => {
    if (localStream) {
      localStream.getTracks().forEach(track => track.stop());
    }
    navigate('/');
  };

  if (loading) {
    return <div className="loading">Loading meeting...</div>;
  }

  return (
    <div className="room-container">
      {/* Meeting Header */}
      <div className="meeting-header">
        <div className="meeting-info">
          <h2>Meeting Room</h2>
          <span className="room-id">ID: {roomId}</span>
          {isHost && <span className="host-badge">Host</span>}
        </div>
        <div className="participant-count">
          <i className="fas fa-users"></i>
          <span>{peers.length + 1}</span>
        </div>
      </div>

      {/* Video Grid */}
      <div className="video-grid">
        {/* Local Video */}
        <div className="video-wrapper">
          <video
            ref={userVideo}
            autoPlay
            muted
            playsInline
            className={`video-element ${isVideoOff ? 'video-off' : ''}`}
          />
          <div className="video-overlay">
            <span className="user-name">
              {user?.name} (You)
              {isHost && <span className="host-tag">Host</span>}
            </span>
            <div className="video-controls-indicators">
              {isAudioMuted && <i className="fas fa-microphone-slash"></i>}
              {isVideoOff && <i className="fas fa-video-slash"></i>}
            </div>
          </div>
        </div>

        {/* Remote Videos */}
        {peers.map(peer => (
          <VideoPlayer
            key={peer.peerId}
            peer={peer.peer}
            userName={peer.userName}
          />
        ))}
      </div>

      {/* Controls */}
      <div className="controls">
        <button 
          className={`control-btn ${isAudioMuted ? 'active' : ''}`}
          onClick={toggleAudio}
        >
          <i className={`fas fa-microphone${isAudioMuted ? '-slash' : ''}`}></i>
        </button>
        <button 
          className={`control-btn ${isVideoOff ? 'active' : ''}`}
          onClick={toggleVideo}
        >
          <i className={`fas fa-video${isVideoOff ? '-slash' : ''}`}></i>
        </button>
        <button className="control-btn leave" onClick={leaveRoom}>
          <i className="fas fa-phone-slash"></i>
        </button>
      </div>
    </div>
  );
}

// VideoPlayer Component
function VideoPlayer({ peer, userName }) {
  const videoRef = useRef();

  useEffect(() => {
    if (!peer) return;

    peer.on('stream', stream => {
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    });

    return () => {
      if (peer && !peer.destroyed) {
        peer.destroy();
      }
    };
  }, [peer]);

  return (
    <div className="video-wrapper">
      <video
        ref={videoRef}
        autoPlay
        playsInline
        className="video-element"
      />
      <div className="video-overlay">
        <span className="user-name">{userName}</span>
      </div>
    </div>
  );
}

export default Room;